}

main();
</code></pre>

Using callbacks functions<pre><code>const mockedRequestCallback = (url, success, failure) =&gt; {
    const delay = Math.floor(Math.random() * 4500) + 500;
    setTimeout(() =&gt; {
        if (delay &gt; 4000) {
            failure("Connection timeout !");
        } else {
            success(`Here is the data from ${url}`);
        }
    }, delay);
};
</code></pre> Using promises<pre><code>const mockedRequestPromise = (url) =&gt; {
    return new Promise((resolve, reject) =&gt; {
        const delay = Math.floor(Math.random() * 4500) + 500;
        setTimeout(() =&gt; {
            if (delay &gt; 4000) {
                reject("Connection timeout !");
            } else {
                resolve(`Here is the data from ${url}`);
            }
        }, delay);
    });
};

const request = mockedRequestPromise("myapi.com/inference");
request
    .then(() =&gt; {
        console.log("Request success ! (resolve)");
    })
    .catch(() =&gt; {
        console.log("Request failure ! (reject)");
    });
</code></pre> Multiple requests using promise<pre><code>mockedRequestPromise("myapi.com/inference/v1")
    .then((data) =&gt; {
        console.log("Request success ! (resolve) - v1");
        console.log(data);
        return mockedRequestPromise("myapi.com/inference/v2");
    })
    .then((data) =&gt; {
        console.log("Request success ! (resolve) - v2");
        console.log(data);
        return mockedRequestPromise("myapi.com/inference/v3");
    })
    .then((data) =&gt; {
        console.log("Request success ! (resolve) - v3");
        console.log(data);
    })
    .catch((err) =&gt; {
        console.log("A request failed !");
        console.log(err);
    });
</code></pre> <ul> <li>Async keyword: The async functions always return a promise. If the function returns a value, the promise will be resolved with that value. If the function throws an exception, the promise will be rejected.</li> <li>Await keyword: This keyword can only be used inside of functions declared with async. This feature will pause the execution of the function, waiting for a promise to be resolved.</li> </ul> Async keyword<pre><code>const login = async (user, pass) =&gt; {
    if (!user || !pass) throw "Missing Credentials !";
    if (pass === "123456") return "Welcome !";
    throw "Invalid Password !";
};

login("foobar", "123456")
    .then((msg) =&gt; {
        console.log("Logged In !");
        console.log(msg);
    })
    .catch((err) =&gt; {
        console.log("Error !");
        console.log(err);
    });
</code></pre> Await keyword<pre><code>async function makeTwoApiRequest() {
    try {
        let data1 = await mockedRequestPromise("myapi.com/inference/v1");
        console.log(data1);
        let data2 = await mockedRequestPromise("myapi.com/inference/v2");
        console.log(data2);
    } catch (err) {
        console.log("Error !");
        console.log(err);
    }
}
</code></pre>
